using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" },
    ];

    private readonly List<Course> _courses;

    public CatalogService()
    {
        _courses =
        [
            new()
            {
                Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
                Description = "An introductory course covering fundamental programming concepts using Python. Topics include variables, control structures, functions, and basic data structures.",
                Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, IsFeatured = true,
                InstructorName = "Dr. Sarah Chen",
                InstructorBio = "Dr. Chen holds a PhD in Computer Science from MIT and has 15 years of teaching experience. Her research focuses on programming language design and CS education."
            },
            new()
            {
                Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms",
                Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs) and algorithm design techniques including sorting, searching, and dynamic programming.",
                Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, IsFeatured = true,
                InstructorName = "Dr. James Park",
                InstructorBio = "Dr. Park is an award-winning educator specializing in algorithm analysis. He previously worked at Google Research before joining the faculty."
            },
            new()
            {
                Id = 3, CourseCode = "CS 310", Title = "Database Systems",
                Description = "Introduction to relational database design, SQL, normalization, transaction processing, and modern NoSQL approaches.",
                Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, IsFeatured = false,
                InstructorName = "Prof. Maria Lopez",
                InstructorBio = "Prof. Lopez brings industry experience from Oracle and MongoDB. She specializes in distributed database systems."
            },
            new()
            {
                Id = 4, CourseCode = "MATH 151", Title = "Calculus I",
                Description = "Limits, continuity, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.",
                Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, IsFeatured = true,
                InstructorName = "Dr. Robert Liu",
                InstructorBio = "Dr. Liu is a mathematician with expertise in applied analysis. He has published extensively on numerical methods."
            },
            new()
            {
                Id = 5, CourseCode = "MATH 250", Title = "Linear Algebra",
                Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues and eigenvectors with applications.",
                Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, IsFeatured = false,
                InstructorName = "Dr. Anna Kowalski",
                InstructorBio = "Dr. Kowalski received her doctorate from Cambridge and researches algebraic geometry and representation theory."
            },
            new()
            {
                Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
                Description = "Mechanics, thermodynamics, and waves. Includes laboratory sessions demonstrating fundamental physical principles.",
                Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM + Lab Thu 2:00–4:50 PM", DepartmentId = 3, IsFeatured = true,
                InstructorName = "Dr. Michael Torres",
                InstructorBio = "Dr. Torres is an experimental physicist with research in condensed matter. He emphasizes hands-on learning."
            },
            new()
            {
                Id = 7, CourseCode = "PHYS 220", Title = "Electromagnetism",
                Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.",
                Credits = 3, Schedule = "Tue/Thu 9:00–10:20 AM", DepartmentId = 3, IsFeatured = false,
                InstructorName = "Dr. Helen Okafor",
                InstructorBio = "Dr. Okafor's research spans quantum electrodynamics and photonics. She is a Fellow of the American Physical Society."
            },
            new()
            {
                Id = 8, CourseCode = "ENG 110", Title = "Academic Writing",
                Description = "Develops skills in critical reading, argumentation, research methods, and clear academic prose across disciplines.",
                Credits = 3, Schedule = "Mon/Wed 9:00–10:20 AM", DepartmentId = 4, IsFeatured = false,
                InstructorName = "Prof. David Kim",
                InstructorBio = "Prof. Kim is a published author and rhetoric scholar dedicated to helping students find their academic voice."
            },
            new()
            {
                Id = 9, CourseCode = "ENG 250", Title = "American Literature",
                Description = "Survey of major American literary works from the colonial period to the present, exploring themes of identity, freedom, and democracy.",
                Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", DepartmentId = 4, IsFeatured = false,
                InstructorName = "Dr. Patricia Nguyen",
                InstructorBio = "Dr. Nguyen specializes in 20th-century American fiction and has authored two books on the Harlem Renaissance."
            },
            new()
            {
                Id = 10, CourseCode = "HIST 101", Title = "World History to 1500",
                Description = "Survey of world civilizations from ancient times through the late medieval period, covering political, social, and cultural developments.",
                Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 5, IsFeatured = false,
                InstructorName = "Dr. Thomas Wright",
                InstructorBio = "Dr. Wright is a medievalist whose research focuses on cross-cultural exchange along the Silk Road."
            },
        ];
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? query, int? departmentId)
    {
        var results = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            results = results.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(query))
        {
            var q = query.Trim().ToLowerInvariant();
            results = results.Where(c =>
                c.Title.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(q, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(q, StringComparison.OrdinalIgnoreCase));
        }

        return results.ToList();
    }
}

